import { Address } from '@circles-sdk/utils';
import { CirclesEvent, CirclesEventType } from './events';

type EventValues = {
  [key: string]: string;
};

export type RcpSubscriptionEvent = {
  event: string;
  values: EventValues;
};

type RpcSubscriptionMessage = RcpSubscriptionEvent[];

const hexToBigInt = (hex: string): bigint => BigInt(hex);
const hexToNumber = (hex: string): number => parseInt(hex, 16);
const hexToUint8Array = (hex: string): Uint8Array => {
  if (hex.length % 2 !== 0) throw new Error('Invalid hex string');
  const array = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    array[i / 2] = parseInt(hex.substr(i, 2), 16);
  }
  return array;
};

const parseEventValues = (event: CirclesEventType, values: EventValues): CirclesEvent => {
  const baseEvent = {
    $event: event,
    blockNumber: hexToNumber(values.blockNumber),
    timestamp: values.timestamp ? hexToNumber(values.timestamp) : undefined,
    transactionIndex: hexToNumber(values.transactionIndex),
    logIndex: hexToNumber(values.logIndex),
    transactionHash: values.transactionHash
  };

  switch (event) {
    case 'CrcV1_HubTransfer':
      return {
        ...baseEvent,
        $event: 'CrcV1_HubTransfer',
        from: values.from as Address,
        to: values.to as Address,
        amount: values.amount ? hexToBigInt(values.amount) : undefined
      };
    case 'CrcV1_Signup':
      return {
        ...baseEvent,
        $event: 'CrcV1_Signup',
        user: values.user as Address,
        token: values.token as Address
      };
    case 'CrcV1_OrganizationSignup':
      return {
        ...baseEvent,
        $event: 'CrcV1_OrganizationSignup',
        organization: values.organization as Address
      };
    case 'CrcV1_Trust':
      return {
        ...baseEvent,
        $event: 'CrcV1_Trust',
        canSendTo: values.canSendTo as Address,
        user: values.user as Address,
        limit: values.limit ? hexToBigInt(values.limit) : undefined
      };
    case 'CrcV1_Transfer':
      return {
        ...baseEvent,
        $event: 'CrcV1_Transfer',
        tokenAddress: values.tokenAddress as Address,
        from: values.from as Address,
        to: values.to as Address,
        amount: values.amount ? hexToBigInt(values.amount) : undefined
      };
    case 'CrcV1_TransferSummary':
      return {
        ...baseEvent,
        $event: 'CrcV1_TransferSummary',
        from: values.from as Address,
        to: values.to as Address,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        events: values.events
      };
    case 'CrcV2_InviteHuman':
      return {
        ...baseEvent,
        $event: 'CrcV2_InviteHuman',
        inviter: values.inviter as Address,
        invited: values.invited as Address
      };
    case 'CrcV2_PersonalMint':
      return {
        ...baseEvent,
        $event: 'CrcV2_PersonalMint',
        human: values.human,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        startPeriod: values.startPeriod ? hexToBigInt(values.startPeriod) : undefined,
        endPeriod: values.endPeriod ? hexToBigInt(values.endPeriod) : undefined
      };
    case 'CrcV2_RegisterGroup':
      return {
        ...baseEvent,
        $event: 'CrcV2_RegisterGroup',
        group: values.group as Address,
        mint: values.mint,
        treasury: values.treasury as Address,
        name: values.name,
        symbol: values.symbol
      };
    case 'CrcV2_RegisterHuman':
      return {
        ...baseEvent,
        $event: 'CrcV2_RegisterHuman',
        avatar: values.avatar as Address,
        inviter: values.inviter as Address
      };
    case 'CrcV2_RegisterOrganization':
      return {
        ...baseEvent,
        $event: 'CrcV2_RegisterOrganization',
        organization: values.organization as Address,
        name: values.name
      };
    case 'CrcV2_Stopped':
      return {
        ...baseEvent,
        $event: 'CrcV2_Stopped',
        avatar: values.avatar as Address
      };
    case 'CrcV2_Trust':
      return {
        ...baseEvent,
        $event: 'CrcV2_Trust',
        truster: values.truster as Address,
        trustee: values.trustee as Address,
        expiryTime: values.expiryTime ? hexToBigInt(values.expiryTime) : undefined
      };
    case 'CrcV2_TransferSingle':
      return {
        ...baseEvent,
        $event: 'CrcV2_TransferSingle',
        operator: values.operator,
        from: values.from as Address,
        to: values.to as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined
      };
    case 'CrcV2_URI':
      return {
        ...baseEvent,
        $event: 'CrcV2_URI',
        value: values.value,
        id: values.id ? hexToBigInt(values.id) : undefined
      };
    case 'CrcV2_ApprovalForAll':
      return {
        ...baseEvent,
        $event: 'CrcV2_ApprovalForAll',
        account: values.account,
        operator: values.operator,
        approved: values.approved === 'true'
      };
    case 'CrcV2_TransferBatch':
      return {
        ...baseEvent,
        $event: 'CrcV2_TransferBatch',
        batchIndex: hexToNumber(values.batchIndex),
        operator: values.operator,
        from: values.from as Address,
        to: values.to as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined
      };
    case 'CrcV2_RegisterShortName':
      return {
        ...baseEvent,
        $event: 'CrcV2_RegisterShortName',
        avatar: values.avatar as Address,
        shortName: values.shortName ? hexToBigInt(values.shortName) : undefined,
        nonce: values.nonce ? hexToBigInt(values.nonce) : undefined
      };
    case 'CrcV2_UpdateMetadataDigest':
      return {
        ...baseEvent,
        $event: 'CrcV2_UpdateMetadataDigest',
        avatar: values.avatar as Address,
        metadataDigest: values.metadataDigest ? hexToUint8Array(values.metadataDigest) : undefined
      };
    case 'CrcV1_UpdateMetadataDigest':
      return {
        ...baseEvent,
        $event: 'CrcV1_UpdateMetadataDigest',
        avatar: values.avatar as Address,
        metadataDigest: values.metadataDigest ? hexToUint8Array(values.metadataDigest) : undefined
      };
    case 'CrcV2_CidV0':
      return {
        ...baseEvent,
        $event: 'CrcV2_CidV0',
        avatar: values.avatar as Address,
        cidV0Digest: values.cidV0Digest ? hexToUint8Array(values.cidV0Digest) : undefined
      };
    case 'CrcV2_CreateVault':
      return {
        ...baseEvent,
        $event: 'CrcV2_CreateVault',
        group: values.group as Address,
        vault: values.vault
      };
    case 'CrcV2_StreamCompleted':
      return {
        ...baseEvent,
        $event: 'CrcV2_StreamCompleted',
        operator: values.operator,
        from: values.from as Address,
        to: values.to as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        amount: values.amount ? hexToBigInt(values.amount) : undefined
      };
    case 'CrcV2_CollateralLockedBatch':
      return {
        ...baseEvent,
        $event: 'CrcV2_CollateralLockedBatch',
        batchIndex: parseInt(values.batchIndex),
        group: values.group as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined,
        userData: values.userData ? hexToUint8Array(values.userData) : undefined
      };
    case 'CrcV2_CollateralLockedSingle':
      return {
        ...baseEvent,
        $event: 'CrcV2_CollateralLockedSingle',
        group: values.group as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined,
        userData: values.userData ? hexToUint8Array(values.userData) : undefined
      };
    case 'CrcV2_GroupMint':
      return {
        ...baseEvent,
        $event: 'CrcV2_GroupMint',
        group: values.group as Address,
        sender: values.sender as Address,
        receiver: values.receiver as Address,
        collateral: values.collateral ? hexToBigInt(values.collateral) : undefined,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
      };
    case 'CrcV2_GroupRedeem':
      return {
        ...baseEvent,
        $event: 'CrcV2_GroupRedeem',
        group: values.group as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined,
        data: values.data ? hexToUint8Array(values.data) : undefined
      };
    case 'CrcV2_GroupRedeemCollateralBurn':
      return {
        ...baseEvent,
        $event: 'CrcV2_GroupRedeemCollateralBurn',
        batchIndex: parseInt(values.batchIndex),
        group: values.group as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined
      };
    case 'CrcV2_GroupRedeemCollateralReturn':
      return {
        ...baseEvent,
        $event: 'CrcV2_GroupRedeemCollateralReturn',
        batchIndex: parseInt(values.batchIndex),
        group: values.group as Address,
        id: values.id ? hexToBigInt(values.id) : undefined,
        value: values.value ? hexToBigInt(values.value) : undefined
      };
    case 'CrcV2_DepositDemurraged':
      return {
        ...baseEvent,
        $event: 'CrcV2_DepositDemurraged',
        account: values.account,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        inflationaryAmount: values.inflationaryAmount ? hexToBigInt(values.inflationaryAmount) : undefined
      };
    case 'CrcV2_DepositInflationary':
      return {
        ...baseEvent,
        $event: 'CrcV2_DepositInflationary',
        account: values.account,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        demurragedAmount: values.demurragedAmount ? hexToBigInt(values.demurragedAmount) : undefined
      };
    case 'CrcV2_WithdrawDemurraged':
      return {
        ...baseEvent,
        $event: 'CrcV2_WithdrawDemurraged',
        account: values.account,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        inflationaryAmount: values.inflationaryAmount ? hexToBigInt(values.inflationaryAmount) : undefined
      };
    case 'CrcV2_WithdrawInflationary':
      return {
        ...baseEvent,
        $event: 'CrcV2_WithdrawInflationary',
        account: values.account,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        demurragedAmount: values.demurragedAmount ? hexToBigInt(values.demurragedAmount) : undefined
      };
    case 'CrcV2_Erc20WrapperTransfer':
      return {
        ...baseEvent,
        $event: 'CrcV2_Erc20WrapperTransfer',
        tokenAddress: values.tokenAddress as Address,
        from: values.from as Address,
        to: values.to as Address,
        amount: values.value ? hexToBigInt(values.value) : undefined
      };
    case 'CrcV2_ERC20WrapperDeployed':
      return {
        ...baseEvent,
        $event: 'CrcV2_ERC20WrapperDeployed',
        avatar: values.avatar as Address,
        erc20Wrapper: values.erc20Wrapper,
        circlesType: values.circlesType ? hexToNumber(values.circlesType) : undefined
      };
    case 'CrcV2_DiscountCost':
      return {
        ...baseEvent,
        $event: 'CrcV2_DiscountCost',
        account: values.account,
        id: values.id ? hexToBigInt(values.id) : undefined,
        cost: values.cost ? hexToBigInt(values.cost) : undefined
      };
    case 'CrcV2_TransferSummary':
      return {
        ...baseEvent,
        $event: 'CrcV2_TransferSummary',
        from: values.from as Address,
        to: values.to as Address,
        amount: values.amount ? hexToBigInt(values.amount) : undefined,
        events: values.events
      };
    case 'CrcV2_FlowEdgesScopeLastEnded':
      return {
        ...baseEvent,
        $event: 'CrcV2_FlowEdgesScopeLastEnded'
      };
    case 'CrcV2_FlowEdgesScopeSingleStarted':
      return {
        ...baseEvent,
        $event: 'CrcV2_FlowEdgesScopeSingleStarted',
        flowEdgeId: values.flowEdgeId ? hexToBigInt(values.flowEdgeId) : undefined,
        streamId: values.streamId ? hexToBigInt(values.streamId) : undefined
      };
    case 'CrcV2_CMGroupCreated':
      return {
        ...baseEvent,
        $event: 'CrcV2_CMGroupCreated',
        proxy: values.proxy as Address,
        owner: values.owner as Address,
        mintHandler: values.mintHandler as Address,
        redemptionHandler: values.redemptionHandler as Address,
        emitter: values.emitter as Address,
        liquidityProvider: values.liquidityProvider as Address
      };
    case 'CrcV2_CirclesBackingDeployed':
      return {
        ...baseEvent,
        $event: 'CrcV2_CirclesBackingDeployed',
        backer: values.backer as Address,
        circlesBackingInstance: values.circlesBackingInstance as Address,
        emitter: values.emitter as Address
      };
    case 'CrcV2_CirclesBackingInitiated':
      return {
        ...baseEvent,
        $event: 'CrcV2_CirclesBackingInitiated',
        backer: values.backer as Address,
        circlesBackingInstance: values.circlesBackingInstance as Address,
        backingAsset: values.backingAsset as Address,
        personalCirclesAddress: values.personalCirclesAddress as Address,
        emitter: values.emitter as Address
      };
    case 'CrcV2_CirclesBackingCompleted':
      return {
        ...baseEvent,
        $event: 'CrcV2_CirclesBackingCompleted',
        backer: values.backer as Address,
        circlesBackingInstance: values.circlesBackingInstance as Address,
        lbp: values.lbp as Address,
        emitter: values.emitter as Address
      };
    case 'CrcV2_LBPDeployed':
      return {
        ...baseEvent,
        $event: 'CrcV2_LBPDeployed',
        circlesBackingInstance: values.circlesBackingInstance as Address,
        lbp: values.lbp as Address,
        emitter: values.emitter as Address
      };
    case 'CrcV2_BaseGroupCreated':
      return {
        ...baseEvent,
        $event: 'CrcV2_BaseGroupCreated',
        group: values.group as Address,
        owner: values.owner as Address,
        mintHandler: values.mintHandler as Address,
        treasury: values.treasury as Address
      };
    case 'CrcV2_BaseGroupOwnerUpdated':
      return {
        ...baseEvent,
        $event: 'CrcV2_BaseGroupOwnerUpdated',
        emitter: values.emitter as Address,
        owner: values.owner as Address
      };
    case 'CrcV2_BaseGroupServiceUpdated':
      return {
        ...baseEvent,
        $event: 'CrcV2_BaseGroupServiceUpdated',
        emitter: values.emitter as Address,
        newService: values.newService as Address
      };
    case 'CrcV2_BaseGroupFeeCollectionUpdated':
      return {
        ...baseEvent,
        $event: 'CrcV2_BaseGroupFeeCollectionUpdated',
        emitter: values.emitter as Address,
        feeCollection: values.feeCollection as Address
      };
    case 'Safe_AddedOwner':
      return {
        ...baseEvent,
        $event: 'Safe_AddedOwner',
        safeAddress: values.safeAddress as Address,
        owner: values.owner as Address
      };
    case 'Safe_ProxyCreation':
      return {
        ...baseEvent,
        $event: 'Safe_ProxyCreation',
        proxy: values.proxy as Address,
        singleton: values.singleton as Address
      };
    case 'Safe_RemovedOwner':
      return {
        ...baseEvent,
        $event: 'Safe_RemovedOwner',
        safeAddress: values.safeAddress as Address,
        owner: values.owner as Address
      };
    case 'Safe_SafeSetup':
      return {
        ...baseEvent,
        $event: 'Safe_SafeSetup',
        safeAddress: values.safeAddress as Address,
        initiator: values.initiator as Address,
        owner: values.owner as Address,
        threshold: values.threshold ? hexToBigInt(values.threshold) : undefined,
        initializer: values.initializer as Address,
        fallbackHandler: values.fallbackHandler as Address
      };
    default:
      return {
        ...baseEvent,
        $event: 'Crc_UnknownEvent',
        originalEventType: event
      };
  }
};

export const parseRpcSubscriptionMessage = (message: RpcSubscriptionMessage): CirclesEvent[] => {
  return message.map(result => parseEventValues(<CirclesEventType>result.event, result.values));
};